const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

let tasksStore = [];

async function getTasks(projectId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    throw new NotFoundError('Project not found', 'PROJECT_NOT_FOUND');
  }
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    throw new NotFoundError('Project not found', 'PROJECT_NOT_FOUND');
  }
  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }
  if (status !== 'todo' && status !== 'done') {
    throw new BadRequestError('Invalid task status', 'INVALID_STATUS');
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  getTasks,
  updateTaskStatus,
};
